/* com.matjzing.mapper.FrontTopicMapper.insertFrontTopic */
INSERT INTO TOPIC (
	  GROUP_SEQ /**/
	, CATEGORY_SEQ /**/
	, TITLE /**/
	, STATUS /**/
	, GOOGLE_EVENT_ID /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{groupSeq}
	, #{categorySeq}
	, #{title}
	, #{status}
	, #{googleEventId}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)
